    if (elem_19 >= blk) return;

    int item_11 = blk - 1 - elem_19;

    // Load reference block into local memory
    // Only need to load if this thread is responsible for this elem_19
    // But since local memory is shared, we need all threads to cooperate or just one thread loads.
    // Original OpenMP code: each thread loads its own slice.
    // Here, each thread (global_id) corresponds to a specific elem_19.
    // So this thread loads the data for its specific elem_19.

    // However, the local arrays are sized for BLOCK_SIZE x BLOCK_SIZE.
    // The original code had each thread loading a full BLOCK_SIZE x BLOCK_SIZE tile for its specific elem_19.
    // Wait, in OpenMP, each thread executed the whole loop for its specific elem_19.
    // In OpenCL, we have one thread per elem_19 (global_id), but we still need to load a BLOCK_SIZE x BLOCK_SIZE tile.
    // So the single thread must load the entire tile? That's inefficient but matches the logic.
    // Or, we can use the local_id to parallelize the loading within the tile for this elem_19.

    // Let's stick to the structure: one thread per elem_19 (global_id).
    // This thread loads the tile for item_11 and elem_19.

    int base_ref_row = item_11 * BLOCK_SIZE + 1;
    int base_ref_col = elem_19 * BLOCK_SIZE + 1;

    for (int i = 0; i < BLOCK_SIZE; ++i) {
        for (int j = 0; j < BLOCK_SIZE; ++j) {
            item_16[i * BLOCK_SIZE + j] = referrence[max_cols * (base_ref_row + i) + base_ref_col + j];
        }
    }

    int base_in_row = item_11 * BLOCK_SIZE;
    int base_in_col = elem_19 * BLOCK_SIZE;

    for (int i = 0; i < BLOCK_SIZE + 1; ++i) {
        for (int j = 0; j < BLOCK_SIZE + 1; ++j) {
            elem_23[i * (BLOCK_SIZE + 1) + j] = input_itemsets[max_cols * (base_in_row + i) + base_in_col + j];
        }
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    // Compute DP block
    for (int i = 1; i < BLOCK_SIZE + 1; ++i) {
        for (int j = 1; j < BLOCK_SIZE + 1; ++j) {
            elem_23[i * (BLOCK_SIZE + 1) + j] = maximum(
                elem_23[(i - 1) * (BLOCK_SIZE + 1) + j - 1] + item_16[(i - 1) * BLOCK_SIZE + j - 1],
