        }
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    // Write results back
    for (int i = 0; i < BLOCK_SIZE; ++i) {
        for (int j = 0; j < BLOCK_SIZE; ++j) {
            input_itemsets[max_cols * (base_ref_row + i) + base_ref_col + j] = elem_23[(i + 1) * (BLOCK_SIZE + 1) + j + 1];
        }
    }
}

